import * as fs from 'fs';
import * as path from 'path';
import { isJsonMode, printJSON, printHuman } from '../utils/output';

const CLEAN_TARGETS = [
    'node_modules',
    '.cache',
    '.next',
    '.nuxt',
    'dist',
    '.turbo',
    '.parcel-cache',
    '.vite',
];

function getDirSize(dirPath: string): number {
    let totalSize = 0;
    try {
        const entries = fs.readdirSync(dirPath, { withFileTypes: true });
        for (const entry of entries) {
            const fullPath = path.join(dirPath, entry.name);
            if (entry.isFile()) {
                totalSize += fs.statSync(fullPath).size;
            } else if (entry.isDirectory()) {
                totalSize += getDirSize(fullPath);
            }
        }
    } catch {
        // permission error or deleted during scan
    }
    return totalSize;
}

function formatBytes(bytes: number): string {
    if (bytes === 0) return '0 B';
    const units = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(1024));
    return `${(bytes / Math.pow(1024, i)).toFixed(1)} ${units[i]}`;
}

export async function clean(
    options: { json?: boolean; dryRun?: boolean; cwd?: string }
): Promise<{ deleted: string[]; freedBytes: number }> {
    const cwd = options.cwd || process.cwd();
    const deleted: string[] = [];
    let freedBytes = 0;

    for (const target of CLEAN_TARGETS) {
        const fullPath = path.join(cwd, target);
        if (fs.existsSync(fullPath)) {
            const size = getDirSize(fullPath);

            if (options.dryRun) {
                printHuman(`  Would delete: ${target} (${formatBytes(size)})`, 'info');
            } else {
                fs.rmSync(fullPath, { recursive: true, force: true });
                printHuman(`  Deleted: ${target} (${formatBytes(size)})`, 'success');
            }

            deleted.push(target);
            freedBytes += size;
        }
    }

    const result = { deleted, freedBytes };

    if (isJsonMode()) {
        printJSON(result);
    } else if (deleted.length === 0) {
        printHuman('Nothing to clean.', 'info');
    } else {
        const verb = options.dryRun ? 'Would free' : 'Freed';
        printHuman(`\n  ${verb} ${formatBytes(freedBytes)} total.`, 'success');
    }

    return result;
}
